INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00010', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '下列題辭與應用場合的配對，何者正確？', '["宜室宜家：新居落成", "道範長存：教師退休", "丕展鴻猷：官員升遷", "德門仁里：醫院開幕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00011', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「清代江南文化市場的發達，讓文人能夠把書畫、詩文等過去修身養性的 才藝，當作謀生之本，不必非要走上科舉出仕的道路。文人賣書畫昔已有 之，但以此為生，並形成職業群體，在這個環境下才真正成型，比如鄭板 橋辭官後，替自己的書畫標價，並不以言商為恥。」 根據上文，下列選項最符合文意的是：', '["清代以前的文人書畫家無不恥於出仕", "文人以書畫修身的傳統已在清代式微", "江南地區促成清代文人書畫的商品化", "從商對清代文人的吸引力遠大於科舉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00012', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「東郭子問莊子：所謂的『道』，究竟在什麼地方？莊子說：無所不在。 東郭子說：請你舉出具體的例子，清楚指明。莊子說：在螻蟻身上。東郭 子說：高妙的『道』，為什麼會在這樣卑下的地方呢？接著莊子又舉了愈 來愈卑下的例子，如：稊稗、磚瓦、屎溺。」（譯自《莊子．知北遊》） 根據上文，下列選項何者最符合莊子之意？', '["「道」是抽象而難以觀察的", "「道」要能脫離生活去體悟", "「道」只存在於卑微的事物中", "愈低微的事物，愈能看出「道」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00013', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「建築藝術自史前時代以來，便一直伴隨著人類。在建築以外，雖曾存在 許多藝術形式，但後來卻消失無蹤。如悲劇曾隨著古希臘人出現，後也因 為他們的沒落而消失，直到文藝復興時期才又再度活躍。這是因為人類一 直都有居住的需求，所以建築藝術從未被擱置一旁。人們會以二種方式來 接受建築物：透過使用和察覺；或更確切地說：透過觸覺和視覺。」 根據上文，下列選項正確的是：', '["人們透過觸覺和嗅覺感知建築藝術", "建築藝術因為古希臘人的沒落而一度中斷", "建築藝術一直伴隨著人類，因為人們有居住的需求", "藝術不曾消失，只是用另一種方式呈現於世人眼前"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00014', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「大多數侍酒師其實天生嗅覺和味覺都沒有那麼敏銳，不適用於卡拉漢的 『嗅覺直覺』策略。為了要通過侍酒大師考試的『品酒』測試，他們通常 從『暴力破解法』開始：盡量增加品嚐的酒類，提高品嚐的頻率，藉由反 覆接觸讓頭腦把酒和味道配對在一起。……相較之下，蕾佩樂媞是以哲學 的策略準備，她說：『我很愛思索「為什麼」，所以酒滿足了我的好奇心。 某款酒的味道「為什麼」是這樣，背後一定有原因，我會以哲學的推論方 法找出來。』」 根據上文，下列選項何者不是成為侍酒師的方法？', '["熟能生巧", "順性而為", "反覆練習", "追根究柢"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00015', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「柯靈烏認為歷史學家必須用審慎的眼光檢視過去，即使這表示要揭露一 些大家珍視已久的迷思。他說：『若歷史和現在毫無關係，那麼過去的歷 史知識對現在就沒什麼幫助。但假設歷史一路影響到現在，那麼即使是塵 封在內部，或乍看之下隱藏於當前矛盾的外表下，這歷史仍然是鮮活且有 影響力的。』」 根據上文，下列選項何者最符合文意？', '["真相始終潛藏在矛盾中，所以歷史仍能鮮活且有影響力", "無論是否對現今社會產生意義，歷史都有其研究的價值", "歷史研究的目的，在於不斷提出新事證以推翻過往定論", "歷史學家不應被既有的迷思所框限，而能致力發掘真相"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00016', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「精緻藝文既能超越時空，『普及化』自能更顯其真價，真正令人憂慮的 是『庸俗化』——無須等到文化創意產業發展法（下稱文創法）施行。許 多新聞只知追求自以為是的爆點，內容卻乏善可陳。多少音樂家活到老學 到老，同一首作品縱使演奏數十年，仍能日新又新，永遠有新發現。但無 論他們在記者會多麼無私分享千錘百鍊後的心得，媒體卻往往只挑那些最 膚淺、和主題最無關、讀後無法增進任何益處的內容來刊登。」 根據上文，下列選項最符合文意的是：', '["文創法的實行會加劇藝文的庸俗化", "新聞曝光度與提升藝文鑑賞力不可一概而論", "媒體的藝文報導滿足了絕大多數民眾的期望", "藝術家不應為了票房而提供與主題無關的訊息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00017', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「史丹福大學心理學家杜維克教授提出，『成見的威脅』是一種讓意志力 減弱的心態，研究中發現，讀了『記憶力隨年齡上升而減弱』文章的人， 和沒有讀過這篇文章的人相較之下，讀過文章的人實際上能記住的單字量 較少。換句話說，『記憶力隨著年紀變大而退化』深植腦中後，人確實會 被這樣的成見影響。」 根據上文，下列選項最符合文意的是：', '["年齡確實是決定意志力強弱的關鍵", "記憶力會隨著年齡增長而不斷退化", "年齡愈長，所累積的成見也會愈多", "成見會減弱人的意志力，無關年齡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00018', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '尼采說：「無論是相愛時、爭執時，還是相互尊敬時，其中一方總是得承 擔各種麻煩事。這些人的共通點，就是個性急躁。個性急躁的人面對任何 情況，總會在事情尚未結束前，就急著反應，做出多餘的言行，導致感情 破裂。所以不管再怎麼簡單平常的事，都會被他們搞成麻煩事。」 根據上文，下列選項最符合文意的是：', '["要懂得放慢生活腳步，才能應付急躁的人", "急躁會為人帶來麻煩，更會影響人際關係", "與人相處要不怕麻煩，才能遠離急躁的人", "急躁的人就是怕麻煩，卻成了別人的麻煩"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00019', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-113-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「一般人提到高齡、老年，通常是負面的評價居多，但是米開朗基羅在八 十八歲時才完成了著名的穹頂設計和圓頂底座建築設計；野獸派畫家馬諦 斯晚年時因為無法站立，必須一直坐在輪椅上，結果竟讓他發明了全新的 剪紙拼貼創作，可見即使人生進入下半場、甚至高齡階段之後，也應該還 是有機會開創新猷。」 根據上文，下列選項何者最符合文意？', '["廉頗老矣，尚能飯否", "家有一老，如有一寶", "莫道桑榆晚，為霞尚滿天", "少壯不努力，老大徒傷悲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:46+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
